   1→//! Agent tools for creating, updating, and deleting personal skills at runtime.
   2→//! Skills are written to `<data_dir>/skills/<name>/SKILL.md` (Personal source).
   3→
   4→use std::{
   5→    collections::HashSet,
   6→    path::{Component, Path, PathBuf},
   7→};
   8→
   9→use {
  10→    async_trait::async_trait,
  11→    moltis_agents::tool_registry::AgentTool,
  12→    serde_json::{Value, json},
  13→};
  14→
  15→use crate::error::Error;
  16→
  17→const MAX_SIDECAR_FILES_PER_CALL: usize = 16;
  18→const MAX_SIDECAR_FILE_BYTES: usize = 128 * 1024;
  19→const MAX_SIDECAR_TOTAL_BYTES: usize = 512 * 1024;
  20→
  21→/// Tool that creates a new personal skill in `<data_dir>/skills/`.
  22→pub struct CreateSkillTool {
  23→    data_dir: PathBuf,
  24→}
  25→
  26→impl CreateSkillTool {
  27→    pub fn new(data_dir: PathBuf) -> Self {
  28→        Self { data_dir }
  29→    }
  30→
  31→    fn skills_dir(&self) -> PathBuf {
  32→        self.data_dir.join("skills")
  33→    }
  34→}
  35→
  36→#[async_trait]
  37→impl AgentTool for CreateSkillTool {
  38→    fn name(&self) -> &str {
  39→        "create_skill"
  40→    }
  41→
  42→    fn description(&self) -> &str {
  43→        "Create a new personal skill. Writes a SKILL.md file to <data_dir>/skills/<name>/. \
  44→         This is persistent workspace storage (not sandbox ~/skills). \
  45→         The skill will be available on the next message automatically."
  46→    }
  47→
  48→    fn parameters_schema(&self) -> Value {
  49→        json!({
  50→            "type": "object",
  51→            "required": ["name", "description", "body"],
  52→            "properties": {
  53→                "name": {
  54→                    "type": "string",
  55→                    "description": "Skill name (lowercase, hyphens, 1-64 chars)"
  56→                },
  57→                "description": {
  58→                    "type": "string",
  59→                    "description": "Short human-readable description"
  60→                },
  61→                "body": {
  62→                    "type": "string",
  63→                    "description": "Markdown instructions for the skill"
  64→                },
  65→                "allowed_tools": {
  66→                    "type": "array",
  67→                    "items": { "type": "string" },
  68→                    "description": "Optional list of tools this skill may use"
  69→                }
  70→            }
  71→        })
  72→    }
  73→
  74→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
  75→        let name = params
  76→            .get("name")
  77→            .and_then(|v| v.as_str())
  78→            .ok_or_else(|| Error::message("missing 'name'"))?;
  79→        let description = params
  80→            .get("description")
  81→            .and_then(|v| v.as_str())
  82→            .ok_or_else(|| Error::message("missing 'description'"))?;
  83→        let body = params
  84→            .get("body")
  85→            .and_then(|v| v.as_str())
  86→            .ok_or_else(|| Error::message("missing 'body'"))?;
  87→        let allowed_tools: Vec<String> = params
  88→            .get("allowed_tools")
  89→            .and_then(|v| v.as_array())
  90→            .map(|arr| {
  91→                arr.iter()
  92→                    .filter_map(|v| v.as_str().map(String::from))
  93→                    .collect()
  94→            })
  95→            .unwrap_or_default();
  96→
  97→        if !moltis_skills::parse::validate_name(name) {
  98→            return Err(Error::message(format!(
  99→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
 100→            ))
 101→            .into());
 102→        }
 103→
 104→        let skill_dir = self.skills_dir().join(name);
 105→        if skill_dir.exists() {
 106→            return Err(Error::message(format!(
 107→                "skill '{name}' already exists; use update_skill to modify it"
 108→            ))
 109→            .into());
 110→        }
 111→
 112→        let content = build_skill_md(name, description, body, &allowed_tools);
 113→        write_skill(&skill_dir, &content).await?;
 114→
 115→        Ok(json!({
 116→            "created": true,
 117→            "path": skill_dir.display().to_string()
 118→        }))
 119→    }
 120→}
 121→
 122→/// Tool that updates an existing personal skill in `<data_dir>/skills/`.
 123→pub struct UpdateSkillTool {
 124→    data_dir: PathBuf,
 125→}
 126→
 127→impl UpdateSkillTool {
 128→    pub fn new(data_dir: PathBuf) -> Self {
 129→        Self { data_dir }
 130→    }
 131→
 132→    fn skills_dir(&self) -> PathBuf {
 133→        self.data_dir.join("skills")
 134→    }
 135→}
 136→
 137→#[async_trait]
 138→impl AgentTool for UpdateSkillTool {
 139→    fn name(&self) -> &str {
 140→        "update_skill"
 141→    }
 142→
 143→    fn description(&self) -> &str {
 144→        "Update an existing personal skill. Overwrites the SKILL.md file."
 145→    }
 146→
 147→    fn parameters_schema(&self) -> Value {
 148→        json!({
 149→            "type": "object",
 150→            "required": ["name", "description", "body"],
 151→            "properties": {
 152→                "name": {
 153→                    "type": "string",
 154→                    "description": "Skill name to update"
 155→                },
 156→                "description": {
 157→                    "type": "string",
 158→                    "description": "New short description"
 159→                },
 160→                "body": {
 161→                    "type": "string",
 162→                    "description": "New markdown instructions"
 163→                },
 164→                "allowed_tools": {
 165→                    "type": "array",
 166→                    "items": { "type": "string" },
 167→                    "description": "Optional new list of allowed tools"
 168→                }
 169→            }
 170→        })
 171→    }
 172→
 173→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 174→        let name = params
 175→            .get("name")
 176→            .and_then(|v| v.as_str())
 177→            .ok_or_else(|| Error::message("missing 'name'"))?;
 178→        let description = params
 179→            .get("description")
 180→            .and_then(|v| v.as_str())
 181→            .ok_or_else(|| Error::message("missing 'description'"))?;
 182→        let body = params
 183→            .get("body")
 184→            .and_then(|v| v.as_str())
 185→            .ok_or_else(|| Error::message("missing 'body'"))?;
 186→        let allowed_tools: Vec<String> = params
 187→            .get("allowed_tools")
 188→            .and_then(|v| v.as_array())
 189→            .map(|arr| {
 190→                arr.iter()
 191→                    .filter_map(|v| v.as_str().map(String::from))
 192→                    .collect()
 193→            })
 194→            .unwrap_or_default();
 195→
 196→        if !moltis_skills::parse::validate_name(name) {
 197→            return Err(Error::message(format!(
 198→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
 199→            ))
 200→            .into());
 201→        }
 202→
 203→        let skill_dir = self.skills_dir().join(name);
 204→        if !skill_dir.exists() {
 205→            return Err(Error::message(format!(
 206→                "skill '{name}' does not exist; use create_skill first"
 207→            ))
 208→            .into());
 209→        }
 210→
 211→        let content = build_skill_md(name, description, body, &allowed_tools);
 212→        write_skill(&skill_dir, &content).await?;
 213→
 214→        Ok(json!({
 215→            "updated": true,
 216→            "path": skill_dir.display().to_string()
 217→        }))
 218→    }
 219→}
 220→
 221→/// Tool that deletes a personal skill from `<data_dir>/skills/`.
 222→pub struct DeleteSkillTool {
 223→    data_dir: PathBuf,
 224→}
 225→
 226→impl DeleteSkillTool {
 227→    pub fn new(data_dir: PathBuf) -> Self {
 228→        Self { data_dir }
 229→    }
 230→
 231→    fn skills_dir(&self) -> PathBuf {
 232→        self.data_dir.join("skills")
 233→    }
 234→}
 235→
 236→#[async_trait]
 237→impl AgentTool for DeleteSkillTool {
 238→    fn name(&self) -> &str {
 239→        "delete_skill"
 240→    }
 241→
 242→    fn description(&self) -> &str {
 243→        "Delete a personal skill. Removes the full skill directory, including supplementary files."
 244→    }
 245→
 246→    fn parameters_schema(&self) -> Value {
 247→        json!({
 248→            "type": "object",
 249→            "required": ["name"],
 250→            "properties": {
 251→                "name": {
 252→                    "type": "string",
 253→                    "description": "Skill name to delete"
 254→                }
 255→            }
 256→        })
 257→    }
 258→
 259→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 260→        let name = params
 261→            .get("name")
 262→            .and_then(|v| v.as_str())
 263→            .ok_or_else(|| Error::message("missing 'name'"))?;
 264→
 265→        if !moltis_skills::parse::validate_name(name) {
 266→            return Err(Error::message(format!("invalid skill name '{name}'")).into());
 267→        }
 268→
 269→        let skill_dir = self.skills_dir().join(name);
 270→
 271→        // Only allow deleting from the personal skills directory.
 272→        let canonical_base = self
 273→            .skills_dir()
 274→            .canonicalize()
 275→            .unwrap_or_else(|_| self.skills_dir().clone());
 276→        let canonical_target = skill_dir
 277→            .canonicalize()
 278→            .unwrap_or_else(|_| skill_dir.clone());
 279→        if !canonical_target.starts_with(&canonical_base) {
 280→            return Err(Error::message("can only delete personal skills").into());
 281→        }
 282→
 283→        if !skill_dir.exists() {
 284→            return Err(Error::message(format!("skill '{name}' not found")).into());
 285→        }
 286→
 287→        tokio::fs::remove_dir_all(&skill_dir).await?;
 288→
 289→        Ok(json!({ "deleted": true }))
 290→    }
 291→}
 292→
 293→/// Tool that writes supplementary text files inside an existing personal skill.
 294→pub struct WriteSkillFilesTool {
 295→    data_dir: PathBuf,
 296→}
 297→
 298→impl WriteSkillFilesTool {
 299→    pub fn new(data_dir: PathBuf) -> Self {
 300→        Self { data_dir }
 301→    }
 302→
 303→    fn skills_dir(&self) -> PathBuf {
 304→        self.data_dir.join("skills")
 305→    }
 306→}
 307→
 308→#[derive(Debug, Clone)]
 309→struct ValidatedSkillFile {
 310→    relative_path: PathBuf,
 311→    content: String,
 312→}
 313→
 314→#[async_trait]
 315→impl AgentTool for WriteSkillFilesTool {
 316→    fn name(&self) -> &str {
 317→        "write_skill_files"
 318→    }
 319→
 320→    fn description(&self) -> &str {
 321→        "Write supplementary UTF-8 text files inside an existing personal skill directory. \
 322→         This tool is disabled by default and only appears when skills.enable_agent_sidecar_files is enabled."
 323→    }
 324→
 325→    fn parameters_schema(&self) -> Value {
 326→        json!({
 327→            "type": "object",
 328→            "required": ["name", "files"],
 329→            "properties": {
 330→                "name": {
 331→                    "type": "string",
 332→                    "description": "Existing skill name to update"
 333→                },
 334→                "files": {
 335→                    "type": "array",
 336→                    "description": "Supplementary text files to write inside the skill directory",
 337→                    "items": {
 338→                        "type": "object",
 339→                        "required": ["path", "content"],
 340→                        "properties": {
 341→                            "path": {
 342→                                "type": "string",
 343→                                "description": "Relative path inside the skill directory"
 344→                            },
 345→                            "content": {
 346→                                "type": "string",
 347→                                "description": "UTF-8 text content to write"
 348→                            }
 349→                        }
 350→                    }
 351→                }
 352→            }
 353→        })
 354→    }
 355→
 356→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 357→        let name = params
 358→            .get("name")
 359→            .and_then(|v| v.as_str())
 360→            .ok_or_else(|| Error::message("missing 'name'"))?;
 361→
 362→        if !moltis_skills::parse::validate_name(name) {
 363→            return Err(Error::message(format!(
 364→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
 365→            ))
 366→            .into());
 367→        }
 368→
 369→        let files = params
 370→            .get("files")
 371→            .and_then(|v| v.as_array())
 372→            .ok_or_else(|| Error::message("missing 'files'"))?;
 373→        let validated = validate_sidecar_files(files)?;
 374→
 375→        let skill_dir = self.skills_dir().join(name);
 376→        if !skill_dir.exists() {
 377→            return Err(Error::message(format!(
 378→                "skill '{name}' does not exist; use create_skill first"
 379→            ))
 380→            .into());
 381→        }
 382→
 383→        write_sidecar_files(&skill_dir, &validated).await?;
 384→        audit_sidecar_file_write(&self.data_dir, name, &validated);
 385→
 386→        Ok(json!({
 387→            "written": true,
 388→            "path": skill_dir.display().to_string(),
 389→            "files_written": validated.len(),
 390→            "files": validated.iter().map(|file| file.relative_path.display().to_string()).collect::<Vec<_>>(),
 391→        }))
 392→    }
 393→}
 394→
 395→fn build_skill_md(name: &str, description: &str, body: &str, allowed_tools: &[String]) -> String {
 396→    let mut frontmatter = format!("---\nname: {name}\ndescription: {description}\n");
 397→    if !allowed_tools.is_empty() {
 398→        frontmatter.push_str("allowed_tools:\n");
 399→        for tool in allowed_tools {
 400→            frontmatter.push_str(&format!("  - {tool}\n"));
 401→        }
 402→    }
 403→    frontmatter.push_str("---\n\n");
 404→    frontmatter.push_str(body);
 405→    if !body.ends_with('\n') {
 406→        frontmatter.push('\n');
 407→    }
 408→    frontmatter
 409→}
 410→
 411→async fn write_skill(skill_dir: &Path, content: &str) -> crate::Result<()> {
 412→    tokio::fs::create_dir_all(skill_dir).await?;
 413→    tokio::fs::write(skill_dir.join("SKILL.md"), content).await?;
 414→    Ok(())
 415→}
 416→
 417→fn validate_sidecar_files(files: &[Value]) -> anyhow::Result<Vec<ValidatedSkillFile>> {
 418→    if files.is_empty() {
 419→        return Err(Error::message("at least one file is required").into());
 420→    }
 421→    if files.len() > MAX_SIDECAR_FILES_PER_CALL {
 422→        return Err(Error::message(format!(
 423→            "too many files: maximum is {MAX_SIDECAR_FILES_PER_CALL}"
 424→        ))
 425→        .into());
 426→    }
 427→
 428→    let mut total_bytes = 0usize;
 429→    let mut seen_paths = HashSet::new();
 430→    let mut validated = Vec::with_capacity(files.len());
 431→
 432→    for file in files {
 433→        let path = file
 434→            .get("path")
 435→            .and_then(|v| v.as_str())
 436→            .ok_or_else(|| Error::message("each file needs a string 'path'"))?;
 437→        let content = file
 438→            .get("content")
 439→            .and_then(|v| v.as_str())
 440→            .ok_or_else(|| Error::message("each file needs a string 'content'"))?;
 441→
 442→        let relative_path = normalize_relative_skill_file_path(path)?;
 443→        if !seen_paths.insert(relative_path.clone()) {
 444→            return Err(Error::message(format!(
 445→                "duplicate file path '{}'",
 446→                relative_path.display()
 447→            ))
 448→            .into());
 449→        }
 450→
 451→        let file_bytes = content.len();
 452→        if file_bytes > MAX_SIDECAR_FILE_BYTES {
 453→            return Err(Error::message(format!(
 454→                "file '{}' exceeds maximum size of {MAX_SIDECAR_FILE_BYTES} bytes",
 455→                relative_path.display()
 456→            ))
 457→            .into());
 458→        }
 459→
 460→        total_bytes += file_bytes;
 461→        if total_bytes > MAX_SIDECAR_TOTAL_BYTES {
 462→            return Err(Error::message(format!(
 463→                "total file content exceeds maximum size of {MAX_SIDECAR_TOTAL_BYTES} bytes"
 464→            ))
 465→            .into());
 466→        }
 467→
 468→        validated.push(ValidatedSkillFile {
 469→            relative_path,
 470→            content: content.to_string(),
 471→        });
 472→    }
 473→
 474→    Ok(validated)
 475→}
