 477→fn normalize_relative_skill_file_path(path: &str) -> anyhow::Result<PathBuf> {
 478→    let trimmed = path.trim();
 479→    if trimmed.is_empty() {
 480→        return Err(Error::message("file path must not be empty").into());
 481→    }
 482→
 483→    let candidate = Path::new(trimmed);
 484→    if candidate.is_absolute() {
 485→        return Err(Error::message("file path must be relative").into());
 486→    }
 487→
 488→    let mut normalized = PathBuf::new();
 489→    for component in candidate.components() {
 490→        match component {
 491→            Component::Normal(segment) => {
 492→                let Some(segment_str) = segment.to_str() else {
 493→                    return Err(Error::message("file path must be valid UTF-8").into());
 494→                };
 495→                if segment_str.starts_with('.') {
 496→                    return Err(Error::message(format!(
 497→                        "hidden path components are not allowed: '{trimmed}'"
 498→                    ))
 499→                    .into());
 500→                }
 501→                normalized.push(segment);
 502→            },
 503→            Component::CurDir => {},
 504→            Component::ParentDir | Component::RootDir | Component::Prefix(_) => {
 505→                return Err(Error::message("path traversal is not allowed").into());
 506→            },
 507→        }
 508→    }
 509→
 510→    let Some(file_name) = normalized.file_name().and_then(|name| name.to_str()) else {
 511→        return Err(Error::message("file path must name a file").into());
 512→    };
 513→
 514→    if file_name.eq_ignore_ascii_case("SKILL.md") {
 515→        return Err(
 516→            Error::message("SKILL.md must be managed with create_skill/update_skill").into(),
 517→        );
 518→    }
 519→
 520→    Ok(normalized)
 521→}
