 523→async fn write_sidecar_files(skill_dir: &Path, files: &[ValidatedSkillFile]) -> crate::Result<()> {
 524→    let canonical_base = tokio::fs::canonicalize(skill_dir).await?;
 525→
 526→    for file in files {
 527→        let target = skill_dir.join(&file.relative_path);
 528→        let parent = target
 529→            .parent()
 530→            .ok_or_else(|| Error::message("invalid file path"))?;
 531→        tokio::fs::create_dir_all(parent).await?;
 532→
 533→        let canonical_parent = tokio::fs::canonicalize(parent).await?;
 534→        if !canonical_parent.starts_with(&canonical_base) {
 535→            return Err(Error::message(
 536→                "can only write inside the personal skill directory",
 537→            ));
 538→        }
 539→
 540→        if let Ok(metadata) = tokio::fs::symlink_metadata(&target).await {
 541→            if metadata.file_type().is_symlink() {
 542→                return Err(Error::message(format!(
 543→                    "refusing to write through symlink '{}'",
 544→                    file.relative_path.display()
 545→                )));
 546→            }
 547→            if metadata.is_dir() {
 548→                return Err(Error::message(format!(
 549→                    "target '{}' is a directory",
 550→                    file.relative_path.display()
 551→                )));
 552→            }
 553→        }
 554→
 555→        let Some(file_name) = file
 556→            .relative_path
 557→            .file_name()
 558→            .and_then(|value| value.to_str())
 559→        else {
 560→            return Err(Error::message("invalid file name"));
 561→        };
 562→        let temp_name = format!(".{file_name}.moltis-tmp-{}", uuid::Uuid::new_v4());
 563→        let temp_path = parent.join(temp_name);
 564→
 565→        tokio::fs::write(&temp_path, &file.content).await?;
 566→        if let Err(error) = tokio::fs::rename(&temp_path, &target).await {
 567→            let _ = tokio::fs::remove_file(&temp_path).await;
 568→            return Err(error.into());
 569→        }
 570→    }
 571→
 572→    Ok(())
 573→}
 574→
 575→fn audit_sidecar_file_write(data_dir: &Path, skill_name: &str, files: &[ValidatedSkillFile]) {
 576→    let dir = data_dir.join("logs");
 577→    let path = dir.join("security-audit.jsonl");
 578→    let now_ms = std::time::SystemTime::now()
 579→        .duration_since(std::time::UNIX_EPOCH)
 580→        .unwrap_or_default()
 581→        .as_millis() as u64;
 582→    let line = serde_json::json!({
 583→        "ts": now_ms,
 584→        "event": "skills.sidecar_files.write",
 585→        "details": {
 586→            "skill": skill_name,
 587→            "files": files.iter().map(|file| {
 588→                serde_json::json!({
 589→                    "path": file.relative_path.display().to_string(),
 590→                    "bytes": file.content.len(),
 591→                })
 592→            }).collect::<Vec<_>>(),
 593→        },
 594→    })
 595→    .to_string();
 596→
 597→    let _ = (|| -> std::io::Result<()> {
 598→        std::fs::create_dir_all(&dir)?;
 599→        let mut file = std::fs::OpenOptions::new()
 600→            .create(true)
 601→            .append(true)
 602→            .open(path)?;
 603→        use std::io::Write as _;
 604→        writeln!(file, "{line}")?;
 605→        Ok(())
 606→    })();
 607→}
